spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var barW = 180;
    var barH = 26;
    var startX = (W - barW) / 2;
    var startY = H / 2 - 35;
    var segmentW = barW / 5;

    // Stages
    // 0 - 2s: stage 1 (whole bar of 80)
    // 2s - 4.5s: stage 2 (divide into 5 parts of 20%)
    // 4.5s - 7s: stage 3 (highlight 1 part as 16)
    // 7s - 9.5s: stage 4 (formula calculation: 0.20 * 80 = 16)
    // 9.5s - 12s: stage 5 (summary)

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.58) stage = 3;
    else if (progress >= 0.58 && progress < 0.79) stage = 4;
    else if (progress >= 0.79) stage = 5;

    // Draw base bar
    ctx.fillStyle = '#1F2937';
    ctx.fillRect(startX, startY, barW, barH);

    // Draw highlighted segments
    var fillWidth = 0;
    if (stage === 3) {
      fillWidth = segmentW;
      ctx.fillStyle = 'rgba(245, 158, 11, 0.7)'; // Yellow-gold
      ctx.fillRect(startX, startY, fillWidth, barH);
    } else if (stage >= 4) {
      fillWidth = segmentW;
      ctx.fillStyle = '#F59E0B';
      ctx.fillRect(startX, startY, fillWidth, barH);
    }

    // Draw segment dividers
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.strokeRect(startX, startY, barW, barH);

    if (stage >= 2) {
      for (var i = 1; i < 5; i++) {
        ctx.beginPath();
        ctx.moveTo(startX + i * segmentW, startY);
        ctx.lineTo(startX + i * segmentW, startY + barH);
        ctx.strokeStyle = '#374151';
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
    }

    // Labels on top of bar segments
    ctx.font = 'bold 10px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    for (var i = 0; i < 5; i++) {
      var tx = startX + i * segmentW + segmentW / 2;
      if (stage === 1) {
        // No internal labels
      } else if (stage === 2) {
        ctx.fillStyle = '#9CA3AF';
        ctx.fillText('20%', tx, startY + barH / 2);
      } else if (stage >= 3) {
        if (i === 0) {
          ctx.fillStyle = '#111827';
          ctx.fillText('16', tx, startY + barH / 2);
        } else {
          ctx.fillStyle = '#9CA3AF';
          ctx.fillText('16', tx, startY + barH / 2);
        }
      }
    }

    // Main outer labels
    ctx.font = 'bold 13px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('Whole Bar = 80', W / 2, startY - 18);

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Representing the Whole', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('The entire bar has a value of 80 (100%)', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Dividing into 5 Equal Parts', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Each part is exactly 20% (1/5) of the bar', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Value of 1 Part (20%)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('80 divided by 5 equals 16. So, 20% of 80 = 16', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#F59E0B';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Decimal Calculation Method', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('20% = 0.20.  Therefore: 0.20 × 80 = 16', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('20% of 80 = 16', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('1/5 of the total value is highlighted', W / 2, H - 22);
    }
  }
};
